```cpp
#include <vector>
#include <priority_queue>
#include <tuple>
#include <climits>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    vector<vector<tuple<long long, long long, long long>>> adj(n);
    for (auto& e : edges) {
        long long u = e[0];
        long long v = e[1];
        long long start = e[2];
        long long end = e[3];
        adj[u].push_back({v, start, end});
    }

    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    vector<long long> dist(n, LLONG_MAX);
    dist[0] = 0;
    pq.push({0, 0});

    while (!pq.empty()) {
        long long current_time = pq.top().first;
        long long u = pq.top().second;
        pq.pop();

        if (current_time > dist[u]) {
            continue;
        }

        if (u == n - 1) {
            return current_time;
        }

        for (auto& edge : adj[u]) {
            long long v = get<0>(edge);
            long long start = get<1>(edge);
            long long end = get<2>(edge);

            long long s = max(current_time, start);
            if (s <= end) {
                long long new_time = s + 1;
                if (new_time < dist[v]) {
                    dist[v] = new_time;
                    pq.push({new_time, v});
                }
            }
        }
    }

    return -1;
}
